import{_ as e,o as a,c as i,ag as o}from"./chunks/framework.BPmc_f4o.js";const u=JSON.parse('{"title":"Applications","description":"","frontmatter":{},"headers":[],"relativePath":"applications/applications.md","filePath":"applications/applications.md"}'),r={name:"applications/applications.md"};function n(s,t,l,d,p,h){return a(),i("div",null,[...t[0]||(t[0]=[o('<p><span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#1565c0;color:#fff;font-size:11px;font-weight:600;">PRO</span></p><h1 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h1><p>An Application is the central orchestration unit of the Pro layer. Every feature module — auth, rate limiting, IP filtering, route policy, properties, collections, automations, webhooks, and emails — is configured independently per application. This lets you serve different clients from the same WordPress installation with completely isolated API surfaces: different auth methods, different data views, different rate limits, different allowed origins.</p><p>You can create as many applications as you need. Each one is independent.</p><hr><h2 id="applications-list" tabindex="-1">Applications List <a class="header-anchor" href="#applications-list" aria-label="Permalink to &quot;Applications List&quot;">​</a></h2><p>The list view is the entry point for managing all your applications.</p><ul><li><strong>Create</strong> a new application with the add button.</li><li><strong>Enable / Disable</strong> an application with the toggle. A confirmation dialog requires you to type the application name before the change is applied — this prevents accidental deactivation of a live application.</li><li><strong>Delete</strong> an application permanently. A confirmation dialog requires you to type the application name before deletion proceeds.</li><li><strong>Open</strong> any application to access its editor and module configuration.</li></ul><p>Once at least one application exists and is enabled, any incoming REST request that does not match a registered application is blocked.</p><hr><h2 id="application-editor" tabindex="-1">Application Editor <a class="header-anchor" href="#application-editor" aria-label="Permalink to &quot;Application Editor&quot;">​</a></h2><p>Each application has its own editor with two areas:</p><h3 id="identity" tabindex="-1">Identity <a class="header-anchor" href="#identity" aria-label="Permalink to &quot;Identity&quot;">​</a></h3><ul><li><strong>Title</strong> — display name used throughout the admin.</li><li><strong>Description</strong> — optional notes for your own reference.</li><li><strong>Enabled</strong> — activate or deactivate the application without deleting it.</li></ul><h3 id="modules" tabindex="-1">Modules <a class="header-anchor" href="#modules" aria-label="Permalink to &quot;Modules&quot;">​</a></h3><p>Each module can be toggled on or off at the application level. A module must also be globally active to take effect. The editor shows a summary of the current configuration for each module and a direct link to its dedicated settings panel.</p><table tabindex="0"><thead><tr><th>Module</th><th>Description</th><th>Doc</th></tr></thead><tbody><tr><td><strong>Auth &amp; Rate Limiting</strong></td><td>Auth methods, allowed origins &amp; IPs, HTTP methods, users and per-user overrides</td><td><a href="/users/users.html">→ Auth &amp; Rate Limit</a></td></tr><tr><td><strong>IP Filtering</strong></td><td>Whitelist / blacklist, CIDR ranges, country blocking</td><td><a href="/ipsfilter/ipsfilter.html">→ IP Filtering</a></td></tr><tr><td><strong>Routes Policy</strong></td><td>Per-route auth, rate limit, disable, user restriction</td><td><a href="/routes/routes.html">→ Routes</a></td></tr><tr><td><strong>Properties &amp; Models</strong></td><td>Response transforms, per-property control, custom schemas</td><td><a href="/models/models.html">→ Properties &amp; Models</a></td></tr><tr><td><strong>Collections</strong></td><td>Per-page limits, drag-and-drop sort order</td><td><a href="/collections/collections.html">→ Collections</a></td></tr><tr><td><strong>Automations</strong></td><td>Event-driven workflows with conditions and actions</td><td><a href="/automations/automations.html">→ Automations</a></td></tr><tr><td><strong>Webhooks</strong></td><td>Outbound webhook entries with event triggers</td><td><a href="/webhooks/webhooks.html">→ Webhooks</a></td></tr><tr><td><strong>Emails</strong></td><td>Transactional email templates with SMTP</td><td><a href="/mails/mails.html">→ Emails</a></td></tr></tbody></table><hr><h2 id="auth-rate-limiting-module" tabindex="-1">Auth &amp; Rate Limiting Module <a class="header-anchor" href="#auth-rate-limiting-module" aria-label="Permalink to &quot;Auth &amp; Rate Limiting Module&quot;">​</a></h2><p>See the dedicated <a href="/users/users.html">Auth &amp; Rate Limiting</a> page for full documentation of application-level defaults, the users list, and the user editor.</p><hr><h2 id="ip-filtering-module" tabindex="-1">IP Filtering Module <a class="header-anchor" href="#ip-filtering-module" aria-label="Permalink to &quot;IP Filtering Module&quot;">​</a></h2><p>Manages IP-based access control for this application.</p><ul><li><strong>Whitelist mode</strong> — only requests from listed IPs or CIDR ranges are allowed through.</li><li><strong>Blacklist mode</strong> — listed IPs or ranges are blocked. Configurable retention time.</li><li><strong>Country blocking</strong> — block or allow requests by country using GeoIP data.</li><li><strong>CIDR support</strong> — define ranges in addition to individual addresses.</li></ul><p>See the dedicated <a href="/ipsfilter/ipsfilter.html">IP Filtering</a> page for full documentation.</p><hr><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><p><strong>Can multiple applications share the same origin?</strong></p><p>Yes. The firewall matches the first enabled application whose origin matches the request. List order determines priority.</p><p><strong>What happens when no application matches a request?</strong></p><p>Once applications are enabled, any request that does not match a registered application is blocked.</p><p><strong>Can I test an application&#39;s policy before enabling it?</strong></p><p>Yes. The Routes module includes a Test panel that lets you fire live requests through the current policy without exposing it to real traffic.</p>',33)])])}const m=e(r,[["render",n]]);export{u as __pageData,m as default};
